// 自分のターンになったら呼ばれるので、操作を選ぶ。先手なら game.turn=0,
// 後手なら game.turn=1 の状態で呼ばれる
Act choose(Game game)
{
    // 時間計測用
    chrono::system_clock::time_point clk = chrono::system_clock::now();

    vector<Act> acts = game.candidateActs();
    int mx = -1e9, mymin = 1e9;
    Act best_act;
    for (Act act : acts)
    {
        Game new_game = game;
        new_game.applyAct(act);
        if (
                /*chmax(mx, new_game.score[game.turn] - new_game.score[!game.turn]) ||*/
            /*(mx == new_game.score[game.turn] - new_game.score[!game.turn] && */chmin(mymin, hyokacul(new_game)))//)
        {
            best_act = act;
        }
    }

    // 時間計測用
    tim_sum += static_cast<double>(chrono::duration_cast<chrono::microseconds>(
                                       chrono::system_clock::now() - clk)
                                       .count() /
                                   1000000.0);
    return best_act;
}

int usrhyokacul(const int &turn, const Game game)
{
    vector<vector<int> > v(9, vector<int>(9, 1e9));
    Game g = game, h;
    g.turn = turn;
    queue<pair<Game, int> > q;
    vector<Act> acts{{0, 0}, {0, 1}, {0, 2}, {0, 3}};
    q.push(make_pair(g, 0));
    while (q.size())
    {

        g = q.front().first;
        if (chmin(v[g.X[turn]][g.Y[turn]], q.front().second))
        {
            if(DEBUG)cout << 'g' << g.X[turn] << ' ' <<g.Y[turn] << ' ';//
            for (Act a : acts)
            {
                if (g.isOK(a))
                {
                    h = g;
                    h.checkAct(a);

            if(DEBUG)cout << 'h' << h.X[turn] << ' ' <<h.Y[turn] << ' ';//
                    q.push(make_pair(h, q.front().second+1));
                    if(DEBUG)cout << ' '<<q.size();//
                }
            }
        }
        q.pop();
    }
    int r = 1e9;
    rep(i, 9) rep(j, 9)
    {
        //
        /*if(DEBUG){
            cout << v[i][j];
            if(j)cout << ' ';
            else cout << endl;
        }*/
        //
        if (game.C[i][j])
            chmin(r, v[i][j]);
    }
    return r;
}

int myturn;

int hyokacul(Game const &game)
{
    int r = usrhyokacul(myturn, game);
    // r -= usrhyokacul(!myturn, game);
    return r;
}

